import ast
import inspect

# Parse the agent file
with open('src/agents/data_acquisition/agent.py', 'r') as f:
    code = f.read()

tree = ast.parse(code)

# Find the _build_prov_record method
for node in ast.walk(tree):
    if isinstance(node, ast.FunctionDef) and node.name == '_build_prov_record':
        # Find the return statement
        for item in ast.walk(node):
            if isinstance(item, ast.Return):
                # Print the keys in the returned dict
                if isinstance(item.value, ast.Dict):
                    keys = []
                    for key in item.value.keys:
                        if isinstance(key, ast.Constant):
                            keys.append(key.value)
                    print(f"Prov record keys: {keys}")
                    print(f"AcquisitionResult fields: source_url, github_commit_hash, sha256_hash, acquisition_timestamp_utc, control_count, strm_mapping_count, ara_artifact_paths, dvc_remote_confirmed")
                    missing = [f for f in ['ara_artifact_paths'] if f not in keys]
                    if missing:
                        print(f"MISSING from prov record: {missing}")
EOF
